#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char S[10005];
        scanf("%s", S);
        int len = strlen(S);
        int pos = -1;
        for (int i = 0; i < len; ++i) {
            if (S[i] == 'W') { pos = i; break; }
        }
        int left = 0, right = 0;
        for (int i = 0; i < pos; ++i) if (S[i] == 'B') ++left;
        for (int i = pos + 1; i < len; ++i) if (S[i] == 'B') ++right;
        if (left == right) printf("Chef\n");
        else printf("Aleksa\n");
    }
    return 0;
}

